BEGIN;
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
COMMIT;

-- Document: JSONB containment with GIN index
CREATE INDEX idx_events_gin ON events USING GIN (data jsonb_path_ops);
SELECT id FROM events WHERE data @> '{"type": "click", "source": "mobile"}';

-- Full-text search
SELECT id, title FROM articles
WHERE to_tsvector('english', title || ' ' || body) @@ plainto_tsquery('postgresql indexing');

-- OLAP: columnar storage via Citus extension
CREATE TABLE metrics (ts TIMESTAMPTZ, value FLOAT) USING columnar;

-- Default GIN: covers all operators (@>, ?, ?|, ?&)
CREATE INDEX idx_events_metadata ON events USING GIN (metadata);

-- jsonb_path_ops: smaller index, containment-only (@> only)
CREATE INDEX idx_events_metadata_path ON events USING GIN (metadata jsonb_path_ops);

-- Verify index usage (look for "Bitmap Index Scan on idx_events_metadata")
EXPLAIN (ANALYZE, BUFFERS)
SELECT * FROM events
WHERE metadata @> '{"status": "active", "region": "eu-west"}';

-- Write-heavy workloads: disable fastupdate for consistent insert latency
CREATE INDEX idx_events_metadata_nowait ON events
  USING GIN (metadata) WITH (fastupdate = off);

