-- 1. Create hypertable
CREATE TABLE metrics (recorded_at TIMESTAMPTZ NOT NULL, sensor_id INT, value DOUBLE PRECISION);
SELECT create_hypertable('metrics', 'recorded_at');

-- 2. Continuous aggregate
CREATE MATERIALIZED VIEW hourly_avg
WITH (timescaledb.continuous) AS
SELECT time_bucket('1 hour', recorded_at) AS bucket,
       sensor_id, avg(value) AS avg_value
FROM metrics
GROUP BY bucket, sensor_id;
SELECT add_continuous_aggregate_policy('hourly_avg', '2 hours', '1 hour', '1 hour');

-- 3. Enable compression on chunks older than 7 days
ALTER TABLE metrics SET (timescaledb.compress, timescaledb.compress_orderby = 'recorded_at DESC');
SELECT add_compression_policy('metrics', INTERVAL '7 days');

-- Normalized base
CREATE TABLE articles (
  id        BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  author_id BIGINT REFERENCES authors(id),
  title     TEXT NOT NULL,
  metadata  JSONB DEFAULT '{}'
);
CREATE INDEX ON articles USING GIN (metadata jsonb_path_ops);

-- Denormalized read layer
CREATE MATERIALIZED VIEW article_feed AS
SELECT a.id, a.title, au.display_name AS author_name,
       a.metadata ->> 'primary_tag' AS tag
FROM   articles a
JOIN   authors au ON au.id = a.author_id;

REFRESH MATERIALIZED VIEW CONCURRENTLY article_feed;

-- Pessimistic: lock row for the full transaction
BEGIN;
SELECT balance FROM accounts WHERE id = $1 FOR UPDATE;
UPDATE accounts SET balance = balance - 100 WHERE id = $1;
COMMIT;

-- Optimistic: detect conflict via version column
BEGIN;
SELECT balance, version FROM accounts WHERE id = $1;
-- application reads version = 7, then:
UPDATE accounts
  SET balance = balance - 100, version = version + 1
  WHERE id = $1 AND version = 7;  -- 0 rows = lost update, retry
COMMIT;

-- Queue consumer: skip rows locked by other workers
SELECT * FROM jobs WHERE status = 'pending'
ORDER BY created_at FOR UPDATE SKIP LOCKED LIMIT 1;

-- Enable Citus extension
CREATE EXTENSION IF NOT EXISTS citus;

-- Distribute on high-cardinality key; Citus hashes across 32 shards
SELECT create_distributed_table('orders', 'user_id');

-- Colocate order_items so JOIN with orders stays node-local
SELECT create_distributed_table('order_items', 'user_id', colocate_with => 'orders');

-- Detect hot shards: high call count on a single shardid = hot spot
SELECT shardid, sum(calls) AS total_calls
FROM citus_stat_statements
GROUP BY shardid
ORDER BY total_calls DESC
LIMIT 5;

-- Rebalance shards across workers when load skews
SELECT rebalance_table_shards('orders');

-- Enable RLS and create a tenant-scoped policy
ALTER TABLE user_data ENABLE ROW LEVEL SECURITY;
ALTER TABLE user_data FORCE ROW LEVEL SECURITY;

CREATE POLICY tenant_isolation ON user_data
  USING (tenant_id = current_setting('app.current_tenant_id')::uuid)
  WITH CHECK (tenant_id = current_setting('app.current_tenant_id')::uuid);

-- Least-privilege app role
CREATE ROLE app_user NOLOGIN;
GRANT SELECT, INSERT, UPDATE ON user_data TO app_user;
REVOKE DELETE ON user_data FROM app_user;

-- Encrypt PII column at write time
INSERT INTO user_data (tenant_id, email_enc)
VALUES (
  current_setting('app.current_tenant_id')::uuid,
  pgp_sym_encrypt('user@example.com', current_setting('app.encryption_key'))
);

-- Phase 1: add nullable (no rewrite, no lock)
ALTER TABLE events ADD COLUMN source TEXT;

-- Phase 2: backfill in batches (adjust range to your table size)
UPDATE events SET source = 'legacy' WHERE id BETWEEN 1 AND 100000 AND source IS NULL;
-- repeat until complete

-- Phase 3a: add constraint without scanning existing rows
ALTER TABLE events
  ADD CONSTRAINT events_source_not_null CHECK (source IS NOT NULL) NOT VALID;

-- Phase 3b: validate under ShareUpdateExclusiveLock (reads/writes still allowed)
ALTER TABLE events VALIDATE CONSTRAINT events_source_not_null;
